class _UnboundTTLCache(TTLCache):

    def __init__(self, ttl, timer):
        TTLCache.__init__(self, maxsize=math.inf, ttl=ttl, timer=timer)

    @property
    def maxsize(self):
        return math.inf


def _cache(cache_factory, maxsize, typed, **kwargs):
    """Internal helper to create a cache decorator."""
    key = keys.typedkey if typed else keys.hashkey
    lock = threading.RLock()

    if maxsize is None:
        if kwargs.get('ttl') is not None or kwargs.get('timer') is not None:
            cache_obj = _UnboundTTLCache(
                ttl=kwargs.get('ttl', 600),
                timer=kwargs.get('timer', time.monotonic),
            )
        elif kwargs.get('choice') is not None:
            cache_obj = RRCache(maxsize=math.inf, choice=kwargs['choice'])
        else:
            cache_obj = cache_factory(maxsize=math.inf)
    else:
        cache_obj = cache_factory(maxsize, **kwargs)

    def decorator(func):
        wrapper = cached(cache_obj, key=key, lock=lock, info=True)(func)
        orig_cache_info = wrapper.cache_info

        def cache_info():
            hits, misses, _, currsize = orig_cache_info()
            return (hits, misses, maxsize, currsize)

        wrapper.cache_info = cache_info
        wrapper.cache_parameters = lambda: {'maxsize': maxsize, 'typed': typed}
        return wrapper

